const DICTS: Record<LangCode, Dict> = { en, ar, es, fr, de, pt, ru, tr, hi, zh, ur, id: id_ };

/* ─────────────────────────────────────────────
   Context + hook
───────────────────────────────────────────── */
interface I18nCtx {
  lang: LangCode;
  setLang: (l: LangCode) => void;
  t: (key: string) => string;
  dir: 'ltr' | 'rtl';
}

const Ctx = createContext<I18nCtx | null>(null);

function detectDefaultLang(): LangCode {
  try {
    const saved = localStorage.getItem(LANG_KEY) as LangCode | null;
    if (saved && DICTS[saved]) return saved;
  } catch {}
  return 'en';
}

export function I18nProvider({ children }: { children: ReactNode }) {
  const [lang, setLangState] = useState<LangCode>(detectDefaultLang);

  const setLang = (l: LangCode) => {
    setLangState(l);
    try { localStorage.setItem(LANG_KEY, l); } catch {}
  };

  const meta = LANGUAGES.find(l => l.code === lang) || LANGUAGES[0];
  const dir: 'ltr' | 'rtl' = meta.rtl ? 'rtl' : 'ltr';

  useEffect(() => {
    document.documentElement.setAttribute('lang', lang);
    document.documentElement.setAttribute('dir', dir);
  }, [lang, dir]);

  const t = (key: string) => DICTS[lang]?.[key] ?? en[key] ?? key;

  return <Ctx.Provider value={{ lang, setLang, t, dir }}>{children}</Ctx.Provider>;
}

export function useI18n() {
  const ctx = useContext(Ctx);
  if (!ctx) throw new Error('useI18n must be used within I18nProvider');
  return ctx;
}
